class DiscGeometry extends Geometry {
  constructor(steps = 4, radius = 1) {
    super();
    steps = Math.max(4, steps);

    const alpha = (2 * Math.PI) / steps;

    this.addVertex(0, 0, 0);
    this.lastVertex.uv[0] = 0.5;
    this.lastVertex.uv[1] = 0.5;

    for (let i = 0; i < steps; ++i) {
      const x = Math.cos(alpha * i);
      const y = Math.sin(alpha * i);
      this.addVertex(radius * x, radius * y, 0);
      this.lastVertex.uv[0] = x * 0.5 + 0.5;
      this.lastVertex.uv[1] = y * 0.5 + 0.5;

      if (i > 0) {
        this.addFace(0, i, i + 1);
      }
    }
    this.addFace(0, steps, 1);
  }
}

function createProgram(gl, shaderSources, transformFeedbackVaryings, attribLocations) {
  const program = gl.createProgram();

  [gl.VERTEX_SHADER, gl.FRAGMENT_SHADER].forEach((type, ndx) => {
    const shader = gl.createShader(type);
    gl.shaderSource(shader, shaderSources[ndx]);
    gl.compileShader(shader);
    const success = gl.getShaderParameter(shader, gl.COMPILE_STATUS);

    if (success) {
      gl.attachShader(program, shader);
    } else {
      console.error(gl.getShaderInfoLog(shader));
      gl.deleteShader(shader);
    }
  });

  if (transformFeedbackVaryings) {
    gl.transformFeedbackVaryings(program, transformFeedbackVaryings, gl.SEPARATE_ATTRIBS);
  }

  if (attribLocations) {
    for (const attrib in attribLocations) {
      gl.bindAttribLocation(program, attribLocations[attrib], attrib);
    }
  }

  gl.linkProgram(program);
  const success = gl.getProgramParameter(program, gl.LINK_STATUS);

  if (success) {
    return program;
  }

  console.error(gl.getProgramInfoLog(program));
  gl.deleteProgram(program);
  return null;
}

function makeVertexArray(gl, bufLocNumElmPairs, indices) {
  const va = gl.createVertexArray();
  gl.bindVertexArray(va);

  for (const [buffer, loc, numElem] of bufLocNumElmPairs) {
    if (loc === -1) continue;
    gl.bindBuffer(gl.ARRAY_BUFFER, buffer);
    gl.enableVertexAttribArray(loc);
    gl.vertexAttribPointer(loc, numElem, gl.FLOAT, false, 0, 0);
  }

  if (indices) {
    const indexBuffer = gl.createBuffer();
    gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, indexBuffer);
    gl.bufferData(gl.ELEMENT_ARRAY_BUFFER, new Uint16Array(indices), gl.STATIC_DRAW);
  }

  gl.bindVertexArray(null);
  return va;
}

function resizeCanvasToDisplaySize(canvas) {
  const dpr = Math.min(2, window.devicePixelRatio);
  const displayWidth = Math.round(canvas.clientWidth * dpr);
  const displayHeight = Math.round(canvas.clientHeight * dpr);
  const needResize = canvas.width !== displayWidth || canvas.height !== displayHeight;
  if (needResize) {
    canvas.width = displayWidth;
    canvas.height = displayHeight;
  }
  return needResize;
}

function makeBuffer(gl, sizeOrData, usage) {
  const buf = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, buf);
  gl.bufferData(gl.ARRAY_BUFFER, sizeOrData, usage);
  gl.bindBuffer(gl.ARRAY_BUFFER, null);
  return buf;
}

function createAndSetupTexture(gl, minFilter, magFilter, wrapS, wrapT) {
  const texture = gl.createTexture();
  gl.bindTexture(gl.TEXTURE_2D, texture);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, wrapS);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, wrapT);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, minFilter);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, magFilter);
  return texture;
}

class ArcballControl {
  isPointerDown = false;
  orientation = quat.create();
  pointerRotation = quat.create();
  rotationVelocity = 0;
  rotationAxis = vec3.fromValues(1, 0, 0);
  snapDirection = vec3.fromValues(0, 0, -1);
  snapTargetDirection;
  EPSILON = 0.1;
  IDENTITY_QUAT = quat.create();

  constructor(canvas, updateCallback) {
    this.canvas = canvas;
    this.updateCallback = updateCallback || (() => null);

    this.pointerPos = vec2.create();
    this.previousPointerPos = vec2.create();
    this._rotationVelocity = 0;
    this._combinedQuat = quat.create();

    canvas.addEventListener('pointerdown', e => {
      vec2.set(this.pointerPos, e.clientX, e.clientY);
      vec2.copy(this.previousPointerPos, this.pointerPos);
      this.isPointerDown = true;
    });
    canvas.addEventListener('pointerup', () => {
      this.isPointerDown = false;
    });
    canvas.addEventListener('pointerleave', () => {
      this.isPointerDown = false;
    });
    canvas.addEventListener('pointermove', e => {
      if (this.isPointerDown) {
        vec2.set(this.pointerPos, e.clientX, e.clientY);
      }
    });

    canvas.style.touchAction = 'none';
  }

  update(deltaTime, targetFrameDuration = 16) {
    const timeScale = deltaTime / targetFrameDuration + 0.00001;
    let angleFactor = timeScale;
    let snapRotation = quat.create();

    if (this.isPointerDown) {
      const INTENSITY = 0.3 * timeScale;
      const ANGLE_AMPLIFICATION = 5 / timeScale;

      const midPointerPos = vec2.sub(vec2.create(), this.pointerPos, this.previousPointerPos);
      vec2.scale(midPointerPos, midPointerPos, INTENSITY);

      if (vec2.sqrLen(midPointerPos) > this.EPSILON) {
        vec2.add(midPointerPos, this.previousPointerPos, midPointerPos);

        const p = this.#project(midPointerPos);
        const q = this.#project(this.previousPointerPos);
        const a = vec3.normalize(vec3.create(), p);
        const b = vec3.normalize(vec3.create(), q);

        vec2.copy(this.previousPointerPos, midPointerPos);

        angleFactor *= ANGLE_AMPLIFICATION;

        this.quatFromVectors(a, b, this.pointerRotation, angleFactor);
      } else {
        quat.slerp(this.pointerRotation, this.pointerRotation, this.IDENTITY_QUAT, INTENSITY);
      }
    } else {
      const INTENSITY = 0.1 * timeScale;
      quat.slerp(this.pointerRotation, this.pointerRotation, this.IDENTITY_QUAT, INTENSITY);

      if (this.snapTargetDirection) {
        const SNAPPING_INTENSITY = 0.2;
        const a = this.snapTargetDirection;
        const b = this.snapDirection;
        const sqrDist = vec3.squaredDistance(a, b);
        const distanceFactor = Math.max(0.1, 1 - sqrDist * 10);
        angleFactor *= SNAPPING_INTENSITY * distanceFactor;
        this.quatFromVectors(a, b, snapRotation, angleFactor);
      }
    }

    const combinedQuat = quat.multiply(quat.create(), snapRotation, this.pointerRotation);
    this.orientation = quat.multiply(quat.create(), combinedQuat, this.orientation);
    quat.normalize(this.orientation, this.orientation);

    const RA_INTENSITY = 0.8 * timeScale;
    quat.slerp(this._combinedQuat, this._combinedQuat, combinedQuat, RA_INTENSITY);
    quat.normalize(this._combinedQuat, this._combinedQuat);

    const rad = Math.acos(this._combinedQuat[3]) * 2.0;
    const s = Math.sin(rad / 2.0);
    let rv = 0;
    if (s > 0.000001) {
      rv = rad / (2 * Math.PI);
      this.rotationAxis[0] = this._combinedQuat[0] / s;
      this.rotationAxis[1] = this._combinedQuat[1] / s;
      this.rotationAxis[2] = this._combinedQuat[2] / s;
    }

    const RV_INTENSITY = 0.5 * timeScale;
    this._rotationVelocity += (rv - this._rotationVelocity) * RV_INTENSITY;
    this.rotationVelocity = this._rotationVelocity / timeScale;

    this.updateCallback(deltaTime);
  }

  quatFromVectors(a, b, out, angleFactor = 1) {
    const axis = vec3.cross(vec3.create(), a, b);
    vec3.normalize(axis, axis);
    const d = Math.max(-1, Math.min(1, vec3.dot(a, b)));
    const angle = Math.acos(d) * angleFactor;
    quat.setAxisAngle(out, axis, angle);
    return { q: out, axis, angle };
  }

  #project(pos) {
    const r = 2;
    const w = this.canvas.clientWidth;
    const h = this.canvas.clientHeight;
    const s = Math.max(w, h) - 1;

    const x = (2 * pos[0] - w - 1) / s;
    const y = (2 * pos[1] - h - 1) / s;
    let z = 0;
    const xySq = x * x + y * y;
    const rSq = r * r;

    if (xySq <= rSq / 2.0) {
      z = Math.sqrt(rSq - xySq);
    } else {
      z = rSq / Math.sqrt(xySq);
    }
    return vec3.fromValues(-x, y, z);
  }
}

class InfiniteGridMenu {
  TARGET_FRAME_DURATION = 1000 / 60;
  SPHERE_RADIUS = 2;

  #time = 0;
  #deltaTime = 0;
  #deltaFrames = 0;
  #frames = 0;
  #lastVideoUpdate = 0;
  #videoUpdateInterval = 1000 / 30; // Update videos at 30fps instead of 60fps
  #isVisible = true;
  #animationId = null;

  camera = {
    matrix: mat4.create(),
    near: 0.1,
    far: 40,
    fov: Math.PI / 4,
    aspect: 1,
    position: vec3.fromValues(0, 0, 3),
    up: vec3.fromValues(0, 1, 0),
    matrices: {
      view: mat4.create(),
      projection: mat4.create(),
      inversProjection: mat4.create()
    }
  };

  nearestVertexIndex = null;
  smoothRotationVelocity = 0;
  scaleFactor = 1.0;
  movementActive = false;

  constructor(canvas, items, onActiveItemChange, onMovementChange, onInit = null) {
    this.canvas = canvas;
    this.items = items || [];
    this.onActiveItemChange = onActiveItemChange || (() => { });
    this.onMovementChange = onMovementChange || (() => { });
    
    // Initialize performance utilities
    this.performanceMonitor = new PerformanceMonitor();
    this.visibilityManager = new VisibilityManager();
    this.resourceManager = new ResourceManager();
    
    // Set up visibility handling
    this.visibilityManager.onVisibilityChange((visible) => {
      this.setVisibility(visible);
    });
    
    this.#init(onInit);
  }

  resize() {
    this.viewportSize = vec2.set(this.viewportSize || vec2.create(), this.canvas.clientWidth, this.canvas.clientHeight);

    const gl = this.gl;
    const needsResize = resizeCanvasToDisplaySize(gl.canvas);
    if (needsResize) {
      gl.viewport(0, 0, gl.drawingBufferWidth, gl.drawingBufferHeight);
    }

    this.#updateProjectionMatrix(gl);
  }

  run(time = 0) {
    // Use integrated performance monitoring
    const fpsUpdated = this.performanceMonitor.updateFPS(time);
    
    if (fpsUpdated) {
      // Update video update interval based on performance
      this.#videoUpdateInterval = this.performanceMonitor.getRecommendedVideoUpdateInterval();
    }
    
    // Skip frames if performance is poor
    if (this.performanceMonitor.shouldSkipFrame()) {
      this.#animationId = requestAnimationFrame(t => this.run(t));
      return;
    }
    
    // Pause animation when tab is not visible
    if (!this.#isVisible) {
      this.#animationId = requestAnimationFrame(t => this.run(t));
      return;
    }

    this.#deltaTime = Math.min(32, time - this.#time);
    this.#time = time;
    this.#deltaFrames = this.#deltaTime / this.TARGET_FRAME_DURATION;
    this.#frames += this.#deltaFrames;

    this.#animate(this.#deltaTime);
    this.#render();

    this.#animationId = requestAnimationFrame(t => this.run(t));
  }

  #init(onInit) {
    this.gl = this.canvas.getContext('webgl2', { antialias: false, alpha: false });
    const gl = this.gl;
    if (!gl) {
      throw new Error('No WebGL 2 context!');
    }

    this.viewportSize = vec2.fromValues(this.canvas.clientWidth, this.canvas.clientHeight);
    this.drawBufferSize = vec2.clone(this.viewportSize);

    this.discProgram = createProgram(gl, [discVertShaderSource, discFragShaderSource], null, {
      aModelPosition: 0,
      aModelNormal: 1,
      aModelUvs: 2,
      aInstanceMatrix: 3
    });

    this.discLocations = {
      aModelPosition: gl.getAttribLocation(this.discProgram, 'aModelPosition'),
      aModelUvs: gl.getAttribLocation(this.discProgram, 'aModelUvs'),
      aInstanceMatrix: gl.getAttribLocation(this.discProgram, 'aInstanceMatrix'),
      uWorldMatrix: gl.getUniformLocation(this.discProgram, 'uWorldMatrix'),
      uViewMatrix: gl.getUniformLocation(this.discProgram, 'uViewMatrix'),
      uProjectionMatrix: gl.getUniformLocation(this.discProgram, 'uProjectionMatrix'),
      uCameraPosition: gl.getUniformLocation(this.discProgram, 'uCameraPosition'),
      uScaleFactor: gl.getUniformLocation(this.discProgram, 'uScaleFactor'),
      uRotationAxisVelocity: gl.getUniformLocation(this.discProgram, 'uRotationAxisVelocity'),
      uTex: gl.getUniformLocation(this.discProgram, 'uTex'),
      uFrames: gl.getUniformLocation(this.discProgram, 'uFrames'),
      uItemCount: gl.getUniformLocation(this.discProgram, 'uItemCount'),
      uAtlasSize: gl.getUniformLocation(this.discProgram, 'uAtlasSize')
    };

    this.discGeo = new DiscGeometry(56, 1);
    this.discBuffers = this.discGeo.data;
    this.discVAO = makeVertexArray(
      gl,
      [
        [makeBuffer(gl, this.discBuffers.vertices, gl.STATIC_DRAW), this.discLocations.aModelPosition, 3],
        [makeBuffer(gl, this.discBuffers.uvs, gl.STATIC_DRAW), this.discLocations.aModelUvs, 2]
      ],
      this.discBuffers.indices
    );

    this.icoGeo = new IcosahedronGeometry();
    this.icoGeo.subdivide(1).spherize(this.SPHERE_RADIUS);
    this.instancePositions = this.icoGeo.vertices.map(v => v.position);
    this.DISC_INSTANCE_COUNT = this.icoGeo.vertices.length;
    this.#initDiscInstances(this.DISC_INSTANCE_COUNT);

    this.worldMatrix = mat4.create();
    this.#initTexture();

    this.control = new ArcballControl(this.canvas, deltaTime => this.#onControlUpdate(deltaTime));

    this.#updateCameraMatrix();
    this.#updateProjectionMatrix(gl);
    this.resize();

    if (onInit) onInit(this);
  }

  #initTexture() {
    const gl = this.gl;
    
    // Use performance monitor for adaptive quality
    const recommendedTextureSize = this.performanceMonitor.getRecommendedTextureSize();
    const maxTextureSize = gl.getParameter(gl.MAX_TEXTURE_SIZE);
    const isHighPerformanceDevice = recommendedTextureSize >= 512 && maxTextureSize >= 4096;
    
    // Use performance-optimized texture filtering
    this.tex = createAndSetupTexture(gl, 
      isHighPerformanceDevice ? gl.LINEAR_MIPMAP_LINEAR : gl.LINEAR, 
      gl.LINEAR, gl.CLAMP_TO_EDGE, gl.CLAMP_TO_EDGE);

    const itemCount = Math.max(1, this.items.length);
    this.atlasSize = Math.ceil(Math.sqrt(itemCount));
    // Use recommended texture size from performance monitor
    this.cellSize = recommendedTextureSize;

    // Store videos for optimized updating
    this.videos = [];
    this.videoNeedsUpdate = new Array(itemCount).fill(true);
    this.videoCanvas = document.createElement('canvas');
    this.videoCtx = this.videoCanvas.getContext('2d', {
      alpha: false,
      willReadFrequently: false,
      desynchronized: true,
      powerPreference: 'default' // Prioritize battery life
    });
    this.videoCanvas.width = this.atlasSize * this.cellSize;
    this.videoCanvas.height = this.atlasSize * this.cellSize;

    // Balanced rendering quality settings
    this.videoCtx.imageSmoothingEnabled = true;
    this.videoCtx.imageSmoothingQuality = isHighPerformanceDevice ? 'high' : 'medium';
    this.textureNeedsUpdate = false;
    
    // Register resources for cleanup
    this.resourceManager.register('texture', this.tex, () => {
      if (this.gl && this.tex) this.gl.deleteTexture(this.tex);
    });
    this.resourceManager.register('videoCanvas', this.videoCanvas, () => {
      if (this.videoCanvas) {
        this.videoCanvas.width = 1;
        this.videoCanvas.height = 1;
      }
    });

    console.log('Creating video texture with items:', this.items);

    Promise.all(
      this.items.map(
        (item, index) =>
          new Promise((resolve) => {
            console.log(`Loading video ${index}:`, item.video);

            const video = document.createElement('video');
            video.crossOrigin = 'anonymous';
            video.muted = true;
            video.playsInline = true;
            video.loop = true;
            video.autoplay = true;
            video.preload = 'auto';
            video.setAttribute('playsinline', 'true');
            video.setAttribute('webkit-playsinline', 'true');
            // Set video quality attributes for better rendering
            video.style.imageRendering = 'high-quality';
            video.style.imageRendering = '-webkit-optimize-contrast';
            video.style.imageRendering = 'crisp-edges';

            video.addEventListener('loadeddata', () => {
              console.log(`Video loaded for item ${index}`);
              clearTimeout(timeoutId);
              // Set performance-optimized playback settings
              video.playbackRate = 1.0;
              video.volume = 0; // Ensure muted for performance
              
              // Track when video actually needs texture updates
              const playPromise = video.play();
              if (playPromise) {
                playPromise.then(() => {
                  console.log(`Video playback started for item ${index}`);
                  this.videoNeedsUpdate[index] = true;
                }).catch(e => {
                  console.log('Autoplay prevented:', e);
                  // Try to play again with user interaction
                  const playOnInteraction = () => {
                    video.play().catch(() => console.log('Retry play failed'));
                    document.removeEventListener('click', playOnInteraction);
                    document.removeEventListener('touchstart', playOnInteraction);
                  };
                  document.addEventListener('click', playOnInteraction, { once: true });
                  document.addEventListener('touchstart', playOnInteraction, { once: true });
                });
              }
              resolve(video);
            });

            video.addEventListener('error', (e) => {
              console.warn(`Video loading error for item ${index}:`, e);
              // Create a fallback colored canvas
              const fallbackCanvas = document.createElement('canvas');
              fallbackCanvas.width = 512;
              fallbackCanvas.height = 512;
              const fallbackCtx = fallbackCanvas.getContext('2d');
              fallbackCtx.fillStyle = '#608B83';
              fallbackCtx.fillRect(0, 0, 512, 512);
              // Mark as canvas for type checking
              fallbackCanvas._isVideoFallback = true;
              resolve(fallbackCanvas);
            });

            // Add timeout fallback to prevent hanging
            const timeoutId = setTimeout(() => {
              console.warn(`Video loading timeout for item ${index}`);
              const fallbackCanvas = document.createElement('canvas');
              fallbackCanvas.width = 512;
              fallbackCanvas.height = 512;
              const fallbackCtx = fallbackCanvas.getContext('2d');
              fallbackCtx.fillStyle = '#608B83';
              fallbackCtx.fillRect(0, 0, 512, 512);
              fallbackCanvas._isVideoFallback = true;
              resolve(fallbackCanvas);
            }, 10000); // 10 second timeout

            video.src = item.video;
            video.load();
          })
      )
    ).then(videos => {
      console.log('All videos loaded:', videos);
      this.videos = videos;
      this.#updateVideoTexture(true); // Force initial update
    }).catch(error => {
      console.error('Error loading video textures:', error);
    });
  }

  #updateVideoTexture(forceUpdate = false) {
    if (!this.videos || this.videos.length === 0) return;
    
    const currentTime = performance.now();
    
    // Throttle video updates based on performance
    if (!forceUpdate && currentTime - this.#lastVideoUpdate < this.#videoUpdateInterval) {
      return;
    }
    
    // Check if any videos actually need updating
    let hasUpdates = forceUpdate;
    if (!hasUpdates) {
      hasUpdates = this.videos.some((video, i) => {
        if (this.videoNeedsUpdate[i] && video.videoWidth && video.videoHeight && !video.paused) {
          // Check if video frame has actually changed
          return video.currentTime !== (video._lastUpdateTime || 0);
        }
        return false;
      });
    }
    
    if (!hasUpdates && !this.textureNeedsUpdate) return;
    
    this.#lastVideoUpdate = currentTime;
    const gl = this.gl;
    const cellSize = this.cellSize;
    let textureUpdated = false;

    this.videos.forEach((video, i) => {
      const x = (i % this.atlasSize) * cellSize;
      const y = Math.floor(i / this.atlasSize) * cellSize;
      
      // Check if this is a video element or canvas fallback
      const isVideo = video && video.tagName === 'VIDEO';
      const isCanvas = video && video.tagName === 'CANVAS';
      
      // Only update if this specific video needs it
      const needsUpdate = forceUpdate || 
                         (this.videoNeedsUpdate[i] && 
                          isVideo && video.currentTime !== (video._lastUpdateTime || 0));
      
      if (!needsUpdate && !isCanvas && !this.textureNeedsUpdate) return;

      try {
        if (isVideo && video.videoWidth && video.videoHeight && !video.paused) {
          this.videoCtx.clearRect(x, y, cellSize, cellSize);
          this.videoCtx.drawImage(video, x, y, cellSize, cellSize);
          video._lastUpdateTime = video.currentTime;
          textureUpdated = true;
        } else if (isCanvas && video.width && video.height) {
          // Fallback canvas
          this.videoCtx.clearRect(x, y, cellSize, cellSize);
          this.videoCtx.drawImage(video, x, y, cellSize, cellSize);
          textureUpdated = true;
        } else if (this.textureNeedsUpdate || forceUpdate) {
          // Fill with default color only if texture needs initialization
          this.videoCtx.fillStyle = '#608B83';
          this.videoCtx.fillRect(x, y, cellSize, cellSize);
          textureUpdated = true;
        }
      } catch (error) {
        // If drawing fails, fill with color only once
        if (this.textureNeedsUpdate || forceUpdate) {
          this.videoCtx.fillStyle = '#608B83';
          this.videoCtx.fillRect(x, y, cellSize, cellSize);
          textureUpdated = true;
        }
      }
    });

    // Only update GPU texture if canvas actually changed
    if (textureUpdated) {
      gl.bindTexture(gl.TEXTURE_2D, this.tex);
      gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, this.videoCanvas);
      
      // Generate mipmaps less frequently for performance
      if (this.textureNeedsUpdate || this.performanceMonitor.metrics.frameCount % 30 === 0) {
        gl.generateMipmap(gl.TEXTURE_2D);
      }
      this.textureNeedsUpdate = false;
    }
  }

  #initDiscInstances(count) {
    const gl = this.gl;
    this.discInstances = {
      matricesArray: new Float32Array(count * 16),
      matrices: [],
      buffer: gl.createBuffer()
    };
    for (let i = 0; i < count; ++i) {
      const instanceMatrixArray = new Float32Array(this.discInstances.matricesArray.buffer, i * 16 * 4, 16);
      instanceMatrixArray.set(mat4.create());
      this.discInstances.matrices.push(instanceMatrixArray);
    }
    gl.bindVertexArray(this.discVAO);
    gl.bindBuffer(gl.ARRAY_BUFFER, this.discInstances.buffer);
    gl.bufferData(gl.ARRAY_BUFFER, this.discInstances.matricesArray.byteLength, gl.DYNAMIC_DRAW);
    const mat4AttribSlotCount = 4;
    const bytesPerMatrix = 16 * 4;
    for (let j = 0; j < mat4AttribSlotCount; ++j) {
      const loc = this.discLocations.aInstanceMatrix + j;
      gl.enableVertexAttribArray(loc);
      gl.vertexAttribPointer(loc, 4, gl.FLOAT, false, bytesPerMatrix, j * 4 * 4);
      gl.vertexAttribDivisor(loc, 1);
    }
    gl.bindBuffer(gl.ARRAY_BUFFER, null);
    gl.bindVertexArray(null);
  }

  #animate(deltaTime) {
    const gl = this.gl;
    this.control.update(deltaTime, this.TARGET_FRAME_DURATION);

    // Update video textures with throttling
    this.#updateVideoTexture();

    let positions = this.instancePositions.map(p => vec3.transformQuat(vec3.create(), p, this.control.orientation));
    const scale = 0.25;
    const SCALE_INTENSITY = 0.6;
    positions.forEach((p, ndx) => {
      const s = (Math.abs(p[2]) / this.SPHERE_RADIUS) * SCALE_INTENSITY + (1 - SCALE_INTENSITY);
      const finalScale = s * scale;
      const matrix = mat4.create();
      mat4.multiply(matrix, matrix, mat4.fromTranslation(mat4.create(), vec3.negate(vec3.create(), p)));
      mat4.multiply(matrix, matrix, mat4.targetTo(mat4.create(), [0, 0, 0], p, [0, 1, 0]));
      mat4.multiply(matrix, matrix, mat4.fromScaling(mat4.create(), [finalScale, finalScale, finalScale]));
      mat4.multiply(matrix, matrix, mat4.fromTranslation(mat4.create(), [0, 0, -this.SPHERE_RADIUS]));

      mat4.copy(this.discInstances.matrices[ndx], matrix);
    });

    gl.bindBuffer(gl.ARRAY_BUFFER, this.discInstances.buffer);
    gl.bufferSubData(gl.ARRAY_BUFFER, 0, this.discInstances.matricesArray);
    gl.bindBuffer(gl.ARRAY_BUFFER, null);

    this.smoothRotationVelocity = this.control.rotationVelocity;
  }

  #render() {
    const gl = this.gl;
    gl.useProgram(this.discProgram);

    gl.enable(gl.CULL_FACE);
    gl.enable(gl.DEPTH_TEST);
    gl.enable(gl.BLEND);
    gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);

    gl.clearColor(0, 0, 0, 0);
    gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);

    gl.uniformMatrix4fv(this.discLocations.uWorldMatrix, false, this.worldMatrix);
    gl.uniformMatrix4fv(this.discLocations.uViewMatrix, false, this.camera.matrices.view);
    gl.uniformMatrix4fv(this.discLocations.uProjectionMatrix, false, this.camera.matrices.projection);
    gl.uniform3f(
      this.discLocations.uCameraPosition,
      this.camera.position[0],
      this.camera.position[1],
      this.camera.position[2]
    );
    gl.uniform4f(
      this.discLocations.uRotationAxisVelocity,
      this.control.rotationAxis[0],
      this.control.rotationAxis[1],
      this.control.rotationAxis[2],
      this.smoothRotationVelocity * 1.1
    );

    gl.uniform1i(this.discLocations.uItemCount, this.items.length);
    gl.uniform1i(this.discLocations.uAtlasSize, this.atlasSize);

    gl.uniform1f(this.discLocations.uFrames, this.#frames);
    gl.uniform1f(this.discLocations.uScaleFactor, this.scaleFactor);
    gl.uniform1i(this.discLocations.uTex, 0);
    gl.activeTexture(gl.TEXTURE0);
    gl.bindTexture(gl.TEXTURE_2D, this.tex);

    gl.bindVertexArray(this.discVAO);
    gl.drawElementsInstanced(
      gl.TRIANGLES,
      this.discBuffers.indices.length,
      gl.UNSIGNED_SHORT,
      0,
      this.DISC_INSTANCE_COUNT
    );
  }

  #updateCameraMatrix() {
    mat4.targetTo(this.camera.matrix, this.camera.position, [0, 0, 0], this.camera.up);
    mat4.invert(this.camera.matrices.view, this.camera.matrix);
  }

  #updateProjectionMatrix(gl) {
    this.camera.aspect = gl.canvas.clientWidth / gl.canvas.clientHeight;
    const height = this.SPHERE_RADIUS * 0.35;
    const distance = this.camera.position[2];
    if (this.camera.aspect > 1) {
      this.camera.fov = 2 * Math.atan(height / distance);
    } else {
      this.camera.fov = 2 * Math.atan(height / this.camera.aspect / distance);
    }
    mat4.perspective(
      this.camera.matrices.projection,
      this.camera.fov,
      this.camera.aspect,
      this.camera.near,
      this.camera.far
    );
    mat4.invert(this.camera.matrices.inversProjection, this.camera.matrices.projection);
  }

  #onControlUpdate(deltaTime) {
    const timeScale = deltaTime / this.TARGET_FRAME_DURATION + 0.0001;
    let damping = 5 / timeScale;
    let cameraTargetZ = 3;

    const isMoving = this.control.isPointerDown || Math.abs(this.smoothRotationVelocity) > 0.01;

    if (isMoving !== this.movementActive) {
      this.movementActive = isMoving;
      this.onMovementChange(isMoving);
    }

    if (!this.control.isPointerDown) {
      const nearestVertexIndex = this.#findNearestVertexIndex();
      const itemIndex = nearestVertexIndex % Math.max(1, this.items.length);
      this.onActiveItemChange(itemIndex);
      const snapDirection = vec3.normalize(vec3.create(), this.#getVertexWorldPosition(nearestVertexIndex));
      this.control.snapTargetDirection = snapDirection;
    } else {
      cameraTargetZ += this.control.rotationVelocity * 80 + 2.5;
      damping = 7 / timeScale;
    }

    this.camera.position[2] += (cameraTargetZ - this.camera.position[2]) / damping;
    this.#updateCameraMatrix();
  }

  #findNearestVertexIndex() {
    const n = this.control.snapDirection;
    const inversOrientation = quat.conjugate(quat.create(), this.control.orientation);
    const nt = vec3.transformQuat(vec3.create(), n, inversOrientation);

    let maxD = -1;
    let nearestVertexIndex;
    for (let i = 0; i < this.instancePositions.length; ++i) {
      const d = vec3.dot(nt, this.instancePositions[i]);
      if (d > maxD) {
        maxD = d;
        nearestVertexIndex = i;
      }
    }
    return nearestVertexIndex;
  }

  #getVertexWorldPosition(index) {
    const nearestVertexPos = this.instancePositions[index];
    return vec3.transformQuat(vec3.create(), nearestVertexPos, this.control.orientation);
  }
  
  // Add cleanup method for proper resource management
  dispose() {
    // Cancel animation frame
    if (this.#animationId) {
      cancelAnimationFrame(this.#animationId);
      this.#animationId = null;
    }
    
    // Clean up all registered resources
    this.resourceManager.cleanup();
    
    // Clean up WebGL resources
    if (this.gl) {
      const gl = this.gl;
      if (this.discProgram) gl.deleteProgram(this.discProgram);
      if (this.discVAO) gl.deleteVertexArray(this.discVAO);
      if (this.discInstances?.buffer) gl.deleteBuffer(this.discInstances.buffer);
    }
    
    // Clean up videos
    if (this.videos) {
      this.videos.forEach(video => {
        // Check if this is actually a video element (not a canvas fallback)
        if (video && video.tagName === 'VIDEO') {
          // Only clear source and reload, no pause to avoid errors
          video.src = '';
          video.load();
        }
      });
      this.videos = [];
    }
  }
  
  // Handle visibility changes for performance
  setVisibility(visible) {
    this.#isVisible = visible;
    // Note: Video pause/play removed to prevent errors with canvas fallbacks
    // Videos will continue playing but texture updates are throttled based on visibility
  }
}

const defaultItems = [
  {
    image: 'https://picsum.photos/900/900?grayscale',
    link: 'https://google.com/',
    title: '',
    description: ''
  }
];

export default function InfiniteMenu({ items = [] }) {
  const canvasRef = useRef(null);
  const sketchRef = useRef(null);
  const navigate = useNavigate();
  const [activeItem, setActiveItem] = useState(null);
  const [isMoving, setIsMoving] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    let sketch;

    const handleActiveItem = index => {
      const itemIndex = index % items.length;
      setActiveItem(items[itemIndex]);
    };

    if (canvas) {
      sketch = new InfiniteGridMenu(canvas, items.length ? items : defaultItems, handleActiveItem, setIsMoving, sk => {
        sketchRef.current = sk;
        sk.run();
      });
    }

    const handleResize = () => {
      if (sketch) {
        sketch.resize();
      }
    };
    
    const handleVisibilityChange = () => {
      if (sketch) {
        sketch.setVisibility(!document.hidden);
      }
    };
    
    // Performance optimizations
    window.addEventListener('resize', handleResize);
    document.addEventListener('visibilitychange', handleVisibilityChange);
    handleResize();

    return () => {
      window.removeEventListener('resize', handleResize);
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      if (sketch) {
        sketch.dispose();
      }
      sketchRef.current = null;
    };
  }, [items]);
  
  // Add cleanup on unmount
  useEffect(() => {
    return () => {
      if (sketchRef.current) {
        sketchRef.current.dispose();
      }
    };
  }, []);

  const handleButtonClick = () => {
    if (!activeItem) return;

    // Find the index of the active item in the items array
    const projectIndex = items.findIndex(item => item.title === activeItem.title);

    if (projectIndex !== -1) {
      // Navigate to the project detail page using the index
      navigate(`/project/${projectIndex}`);
    } else if (activeItem.link) {
      // Fallback to external link if it exists
      if (activeItem.link.startsWith('http')) {
        window.open(activeItem.link, '_blank');
      } else {
        console.log('Internal route:', activeItem.link);
      }
    }
  };

  return (
    <div style={{ position: 'relative', width: '100%', height: '100%', zIndex: 5 }}>
      <canvas id="infinite-grid-menu-canvas" ref={canvasRef} />

      {activeItem && (
        <>

          <h2 className={`face-title ${isMoving ? 'inactive' : 'active'}`}>
            <div>{activeItem.title}</div>
          </h2>
          <ScrambleText onClick={handleButtonClick} className={`action-button ${isMoving ? 'inactive' : 'active'}`}>
            View Project
          </ScrambleText>
        </>
      )}
    </div>
  );
}